                        items: {
                            type: Type.OBJECT,
                            properties: {
                                name: { type: Type.STRING, description: "Az egyedi funkció neve." },
                                description: { type: Type.STRING, description: "Az egyedi funkció rövid leírása." },
                                price: { type: Type.NUMBER, description: "Az egyedi funkció becsült ára." },
